+     * @param destinationDir target extraction directory
+     * @param entryName name of the zip entry
+     * @return File pointing to the safe extraction location
+     * @throws IOException if the entry would be extracted outside destinationDir
+     */
+    private static File safeNewFile(File destinationDir, String entryName) throws IOException
+    {
+      if (entryName == null)
+      {
+        throw new IOException("Zip entry has null name");
+      }
+
+      // Normalize separators to platform default, but treat zip entries as using '/'
+      String normalized = entryName.replace('\\', '/');
+      // Remove any leading "/" so the name is not treated as absolute
+      while (normalized.startsWith("/"))
+      {
+        normalized = normalized.substring(1);
+      }
+
+      File destFile = new File(destinationDir, normalized);
+
+      String destDirCanonical = destinationDir.getCanonicalPath();
+      String destFileCanonical = destFile.getCanonicalPath();
+
+      // Ensure destFileCanonical starts with destDirCanonical + separator or equals destDirCanonical
+      if (!destFileCanonical.equals(destDirCanonical) &&
+          !destFileCanonical.startsWith(destDirCanonical + File.separator))
+      {
+        throw new IOException("Entry is outside of the target dir: " + entryName);
+      }
