+export default function extractQueryParams(req: Request, res: Response, next: NextFunction) {
+  const query = req.query as Record<string, unknown>;
+
+  const rawUrl = typeof query.url === 'string' ? query.url : undefined;
+  if (!rawUrl) {
+    return res.status(400).send('url query parameter is required');
+  }
+
+  let parsedUrl: URL;
+  try {
+    parsedUrl = new URL(rawUrl);
+  } catch {
+    return res.status(400).send('url is not a valid URL');
+  }
+
+  // Only allow http and https schemes
+  if (parsedUrl.protocol !== 'http:' && parsedUrl.protocol !== 'https:') {
+    return res.status(400).send('url must use http or https protocol');
+  }
+
+  const rawFile = typeof query.file === 'string' ? query.file : 'screenshot.png';
