+  // Disallow absolute paths, traversal segments, or any path separators.
+  // We intentionally only allow a simple filename (no directories).
+  if (path.isAbsolute(rawFile) || rawFile.includes('..') || rawFile.includes('/') || rawFile.includes('\\')) {
